import math

def myAtoi(s: str) -> int:
    INT_MIN, INT_MAX = -(2 ** 31), 2 ** 31 - 1
    i, n = 0, len(s)

    # Skip leading spaces
    while i < n and s[i] == ' ':
        i += 1

    if i == n:
        return 0

    # Read optional sign
    negative = False
    if s[i] in ('+', '-'):
        negative = s[i] == '-'
        i += 1

    result = 0
    while i < n and s[i].isdigit():
        result = result * 10 + int(s[i])
        if negative and -result <= INT_MIN:
            return INT_MIN
        if not negative and result >= INT_MAX:
            return INT_MAX
        i += 1

    return -result if negative else result
